insert into wa_quick_replies (trigger, title, body, category, sort_order) values
  (E'/наурыз', E'🏦 Наурыз (7-20-25)', E'{{имя}}, коротко про Наурыз 👇\n\n• Ставка — от 7% годовых (ниже рыночной)\n• Первоначальный взнос — от 20%\n• Срок — до 25 лет\n\nПрограмма государственная, condition меняются — считаю под ваш доход и говорю, проходите ли. Прислать расчёт?', E'programs', 41),
  (E'/отбасы', E'🏦 Отбасы банк', E'{{имя}}, Отбасы — это про накопления 🏦\n\nКопите на депозите, получаете господдержку (премию), затем — жилищный заём под низкий процент.\n\nПодходит, если хотите планомерно, без большого первоначального сразу. Есть депозит в Отбасы или только планируете? Разберём вашу ситуацию.', E'programs', 42),
  (E'/госпрограммы', E'🏦 Обзор госпрограмм', E'{{имя}}, какие госпрограммы сейчас работают 👇\n\n• Наурыз — ставка от 7%, взнос от 20%\n• Отбасы — накопительная система\n• Военная — для военнослужащих\n• Программы для бюджетников и молодых семей\n\nПод каждую — свои требования. Скажите пару слов о себе (доход, сфера) — подберу, что вам подходит.', E'programs', 43),
  (E'/военная', E'🏦 Военная ипотека', E'{{имя}}, если вы военнослужащий — есть отдельная программа с льготными условиями и участием государства 🎖\n\nНужен ли большой первоначальный, какая ставка и сумма — зависит от выслуги и статуса. Уточните, где служите, — посчитаю точно.', E'programs', 44),
  (E'/рефинанс', E'🏦 Рефинансирование', E'{{имя}}, если у вас уже есть ипотека под высокий процент — её можно рефинансировать 🔄\n\nСмысл: переносим кредит в банк с меньшей ставкой → платёж падает, переплата уменьшается.\n\nПришлите текущий график/условия — посчитаю, есть ли выгода именно в вашем случае.', E'programs', 45),
  (E'/переуступка', E'🏦 Переуступка (уступка прав)', E'{{имя}}, переуступка — это покупка квартиры в строящемся доме у того, кто купил её раньше по ДДУ 🏗\n\nЧасто дешевле, чем напрямую у застройщика на позднем этапе. Но нужна проверка договора и застройщика — этим и занимаемся.\n\nЕсть конкретный объект на примете? Скину, на что смотреть.', E'programs', 46),
  (E'/безпв', E'🏦 Без первоначального взноса', E'{{имя}}, «без первоначального» — реально в нескольких случаях 👇\n\n• под залог имеющейся недвижимости\n• программы застройщиков (рассрочка на взнос)\n• использование депозита Отбасы как взноса\n\nПолностью «с нуля» банки почти не дают, но варианты снизить взнос есть. Расскажите, что у вас есть из активов, — подберу.', E'programs', 47),
  (E'/первичка', E'🏦 Первичка или вторичка', E'{{имя}}, коротко разница 👇\n\n• Первичка (новостройка) — часто ниже цена, госпрограммы, но ждать сдачи\n• Вторичка — заезжаете сразу, больше выбор районов, но условия по ставке бывают строже\n\nЧто вам важнее — заехать сразу или сэкономить? Подберу программу под выбор.', E'programs', 48),
  (E'/жасыл', E'🏦 Жасыл (энергоэффективное жильё)', E'{{имя}}, Жасыл — программа на энергоэффективное жильё с льготными условиями 🌿\n\nЕсли объект подходит под критерии — ставка ниже. Скажите, какой дом/ЖК рассматриваете, — проверю, попадает ли под программу.', E'programs', 49),
  (E'/рассрочка50', E'🏦 Рассрочка от застройщика (50/50, 30/70)', E'{{имя}}, многие застройщики дают рассрочку без банка 🏗\n\nНапример: 50% сейчас, 50% до сдачи. Или 30/70. Без процентов, но срок короче ипотеки.\n\nПодходит, если есть значительная сумма сейчас. Скажу, у каких застройщиков сейчас лучшие условия. Какой бюджет?', E'programs', 50),
  (E'/нетпв', E'🛡 «Нет первоначального взноса»', E'{{имя}}, это решаемо чаще, чем кажется 👇\n\n• залог имеющейся недвижимости вместо взноса\n• депозит Отбасы как первоначальный\n• рассрочка застройщика на сам взнос\n\nРасскажите, что есть из активов и какой доход, — посчитаю реальный вариант. Возможно, вы ближе к сделке, чем думаете.', E'objection', 51),
  (E'/плохаяки', E'🛡 «У меня плохая кредитная история»', E'{{имя}}, «плохая» — понятие растяжимое 🩺\n\nОдно дело — старая закрытая просрочка, другое — активная. Часто историю можно подлечить: закрыть мелочь, дождаться обновления, зайти в правильный банк.\n\nДавайте поднимем вашу КИ и посмотрим реальную картину. Может, всё не так страшно.', E'objection', 52),
  (E'/серый', E'🛡 «Доход серый / не подтверждается»', E'{{имя}}, понимаю — это частый случай 👇\n\nЕсть банки и программы, которые смотрят не только на официальную справку: обороты по карте, депозит, подтверждение от работодателя.\n\nРасскажите, как получаете доход, — подскажу, где на это смотрят проще. Вслепую подавать не будем.', E'objection', 53),
  (E'/высокийплатеж', E'🛡 «Платёж высокий, не потяну»', E'{{имя}}, платёж почти всегда можно снизить 👇\n\n• увеличить срок → меньше в месяц\n• другая программа с низкой ставкой\n• больше первоначальный → меньше кредит\n\nСкажите, какой платёж для вас комфортный в месяц, — подберу вариант под эту цифру.', E'objection', 54),
  (E'/многокредитов', E'🛡 «У меня уже много кредитов»', E'{{имя}}, нагрузка — это то, с чем мы работаем в первую очередь 👇\n\nИногда достаточно закрыть одну мелкую рассрочку или карту, чтобы банк увидел вас иначе и одобрил.\n\nДавайте посмотрим вашу нагрузку по БКИ — покажу, что именно тянет вниз и что реально закрыть.', E'objection', 55),
  (E'/самозанятый', E'🛡 «Я ИП / самозанятый»', E'{{имя}}, для ИП и самозанятых ипотека тоже реальна 👇\n\nБанки смотрят на обороты, налоговые отчисления, стабильность. Где-то проще, где-то строже.\n\nСкажите, сколько работаете как ИП и какие обороты примерно, — подскажу банки, которые лояльны к вашему статусу.', E'objection', 56),
  (E'/возраст', E'🛡 «Возраст — дадут ли ипотеку?»', E'{{имя}}, возраст — не стоп 👍\n\nБанки выдают так, чтобы кредит закрывался до определённого возраста, но вариантов много: срок, созаёмщик, программа.\n\nСкажите ваш возраст и желаемый срок — посчитаю, что реально одобрят.', E'objection', 57),
  (E'/декрет', E'🛡 «Я в декрете / отпуске по уходу»', E'{{имя}}, в декрете сложнее, но не безнадёжно 👇\n\nОбычно основным заёмщиком делаем супруга, вас — созаёмщиком. Или ждём выход на работу и готовим заявку заранее.\n\nРасскажите про доход семьи — подскажу, как выстроить заявку, чтобы одобрили.', E'objection', 58),
  (E'/запросдоков', E'📋 Запрос документов', E'{{имя}}, для подачи заявки соберите, пожалуйста 👇\n\n✅ Удостоверение личности\n✅ Справка о доходах / выписка ОПВ\n✅ Справка о семейном положении\n✅ Данные по действующим кредитам\n\nМожно сфотографировать и прислать сюда. Что-то из списка вызывает вопрос?', E'process', 59),
  (E'/напомнидок', E'📋 Напоминание принести документ', E'{{имя}}, добрый день 🙂 Напоминаю: для продолжения не хватает пары документов.\n\nКак будет минутка — сфотографируйте и пришлите сюда. Как только получу — двигаемся дальше по заявке.', E'process', 60),
  (E'/оценка', E'📋 Оценка недвижимости', E'{{имя}}, следующий шаг — оценка квартиры 🏠\n\nЭто обязательное требование банка: независимый оценщик определяет рыночную стоимость. Занимает 1-2 дня.\n\nОрганизуем и сопроводим. Адрес объекта уже есть? Запускаем оценку.', E'process', 61),
  (E'/нотариус', E'📋 Запись к нотариусу', E'{{имя}}, переходим к нотариусу — оформление договора купли-продажи 📝\n\nНужно ваше присутствие и удостоверение личности (продавца — тоже). Обычно занимает 1-2 часа.\n\nКогда вам удобно — утро или после обеда? Согласую время и пришлю адрес.', E'process', 62),
  (E'/оформистраховку', E'📋 Оформление страховки', E'{{имя}}, по ипотеке нужна страховка — это требование банка 🛡\n\nОформим вместе, подберу выгодный вариант (стоимость зависит от суммы и объекта). Без страховки банк не выдаёт.\n\nЗаймёмся на этапе перед выдачей — просто держите в курсе, я напомню заранее.', E'process', 63),
  (E'/регистрация', E'📋 Регистрация сделки', E'{{имя}}, финальный шаг оформления — регистрация договора в гос.органе 🏛\n\nПосле неё вы официально собственник. Обычно 1-3 рабочих дня.\n\nСопровождаю на этом этапе — от вас минимум действий. Как только зарегистрируют — сообщу сразу.', E'process', 64),
  (E'/допдоки', E'📋 Банк запросил доп. документы', E'{{имя}}, банк по вашей заявке попросил дополнительно уточнить пару моментов — это нормальная часть процесса, не отказ 👍\n\nНужно донести: [укажу конкретно]. Соберём — и заявка идёт дальше. Помогу с каждым пунктом.', E'process', 65),
  (E'/готовасделка', E'📋 Приглашение на сделку', E'{{имя}}, отличная новость — всё готово к сделке! 🎉\n\nОсталось встретиться, подписать документы и провести расчёт. Займёт несколько часов.\n\nКогда вам удобно на этой неделе? Согласую с банком и продавцом, пришлю точное время и адрес.', E'process', 66),
  (E'/выдача', E'📋 Выдача денег', E'{{имя}}, подходим к выдаче — банк перечисляет средства продавцу 💰\n\nПосле этого сделка завершена, квартира ваша. Я сопровождаю до этого момента и проверяю, что всё прошло чисто.\n\nПочти у цели! 🔑', E'process', 67),
  (E'/ключи', E'📋 Поздравление с покупкой', E'{{имя}}, поздравляю — теперь вы собственник! 🎉🔑\n\nБыло приятно вести вашу сделку. Если появятся вопросы по документам или в будущем понадобится рефинансирование — я на связи.\n\nИ буду благодарен, если порекомендуете меня друзьям 🙏 Новоселья!', E'process', 68),
  (E'/реквизиты', E'💳 Реквизиты для оплаты', E'{{имя}}, реквизиты для оплаты услуг 👇\n\n[Kaspi / карта / счёт — вписать]\nСумма: {{сумма}} ₸\n\nПосле оплаты пришлите скрин чека сюда — подтвержу и продолжим работу по заявке.', E'payment', 69),
  (E'/планоплаты', E'💳 План оплаты по месяцам', E'{{имя}}, оплату услуг можно разбить по месяцам 👇\n\nПолная сумма: {{сумма}} ₸\nНапример:\n• 3 месяца — по [сумма/3] ₸\n• 6 месяцев — по [сумма/6] ₸\n\nЧасть можно удержать из зарплаты, часть внести самому — посчитаю точно под ваш срок. На сколько месяцев удобно?', E'payment', 70),
  (E'/напомниоплату', E'💳 Напоминание об оплате', E'{{имя}}, добрый день 🙂 Напоминаю про оплату за услуги — {{сумма}} ₸.\n\nКак будет удобно, переведите по реквизитам и пришлите чек. Если нужно разбить на части — скажите, подберём комфортный график.', E'payment', 71),
  (E'/оплатаполучена', E'💳 Оплата получена', E'{{имя}}, оплату получил, спасибо! ✅\n\nВсё зафиксировал. Продолжаю работу по вашей заявке — держу в курсе на каждом шаге.', E'payment', 72),
  (E'/просрочкаоплаты', E'💳 Мягко про просрочку оплаты', E'{{имя}}, добрый день 🙂 Вижу, оплата за услуги пока не прошла.\n\nЕсли возникли сложности — давайте обсудим, можно разбить на части. Просто не хочу останавливать работу по вашей заявке. Как вам удобно?', E'payment', 73),
  (E'/подтвердивстречу', E'📅 Подтверждение встречи', E'{{имя}}, напоминаю про нашу встречу {{дата}} в {{время}} 📅\n\nВсё в силе? Если нужно перенести — просто напишите, подберём другое время. Буду ждать!', E'meeting', 74),
  (E'/непришел', E'📅 Клиент не пришёл', E'{{имя}}, мы договаривались о встрече, но вы не смогли подойти — ничего страшного, бывает 🙂\n\nДавайте перенесём? Скажите, когда вам удобно, — подстроюсь.', E'meeting', 75),
  (E'/переносвстречи', E'📅 Перенос встречи', E'{{имя}}, без проблем перенесём встречу 👍\n\nПредложите день и время, которое вам подходит, — согласую и подтвержу.', E'meeting', 76),
  (E'/онлайнконсультация', E'📅 Онлайн-консультация', E'{{имя}}, необязательно ехать — можем провести консультацию онлайн 💻\n\nСозвонимся по видео в WhatsApp, покажу расчёты на экране, отвечу на вопросы. Займёт 20-30 минут.\n\nКогда вам удобно? Пришлю ссылку/наберу в назначенное время.', E'meeting', 77),
  (E'/прогрев', E'🌱 Прогрев холодного лида', E'{{имя}}, добрый день 🙂 Мы общались по ипотеке некоторое время назад.\n\nУсловия по программам и ставки периодически меняются — если тема ещё актуальна, могу освежить расчёт под текущие условия. Посмотрим?', E'nurture', 78),
  (E'/неготов', E'🌱 «Пока не готов» — на будущее', E'{{имя}}, понял, сейчас не время — это нормально 👍\n\nОставлю вас на контроле. Когда решите вернуться к вопросу — просто напишите, продолжим с того же места. А если появятся выгодные программы — сообщу, без спама.', E'nurture', 79),
  (E'/праздник', E'🌱 Поздравление с праздником', E'{{имя}}, поздравляю с праздником! 🎉\n\nЖелаю вам и близким здоровья, достатка и, конечно, собственного уютного дома 🏡 Если решите заняться жильём — я рядом.', E'nurture', 80),
  (E'/отзыв', E'🌱 Запрос отзыва', E'{{имя}}, было приятно с вами работать! 🙏\n\nЕсли остались довольны — буду очень благодарен за короткий отзыв. Он помогает другим людям решиться. Достаточно пары слов сюда или по ссылке, которую пришлю.', E'nurture', 81),
  (E'/реферал', E'🌱 Реферальная программа', E'{{имя}}, если среди ваших знакомых кто-то думает про ипотеку — порекомендуйте меня 🤝\n\nПомогу им так же честно, а вам — приятный бонус за рекомендацию. Просто дайте контакт или отправьте им мой номер. Спасибо!', E'nurture', 82),
  (E'/возврат', E'🌱 Возврат старого клиента', E'{{имя}}, здравствуйте! Давно не общались 🙂\n\nПоявились новые программы и условия — возможно, сейчас вам подойдёт то, что раньше не проходило. Или нужна помощь по действующей ипотеке (рефинанс, вопросы). Актуально?', E'nurture', 83),
  (E'/чтонужно', E'ℹ️ Что нужно для ипотеки', E'{{имя}}, чтобы получить ипотеку, обычно нужны 3 вещи 👇\n\n1️⃣ Подтверждаемый доход (официальный или обороты)\n2️⃣ Первоначальный взнос (или актив под залог)\n3️⃣ Приемлемая кредитная история\n\nДаже если чего-то не хватает — часто есть обходной путь. Расскажите про себя, посмотрим вашу картину.', E'info', 84),
  (E'/сроки', E'ℹ️ Сроки оформления', E'{{имя}}, по срокам ориентир такой 👇\n\n• Подготовка и подача — 3-7 дней\n• Решение банка — 1-5 рабочих дней\n• Оценка, нотариус, регистрация — 1-2 недели\n\nИтого от заявки до ключей обычно 2-4 недели. Я веду вас на каждом шаге, чтобы не затягивалось.', E'info', 85),
  (E'/разницапрограмм', E'ℹ️ Разница программ кратко', E'{{имя}}, если совсем коротко 👇\n\n• Наурыз — низкая ставка (от 7%), взнос от 20%\n• Отбасы — сначала копите, потом заём\n• Рыночная ипотека — быстрее, но ставка выше\n• Рассрочка застройщика — без банка, короткий срок\n\nЧто подходит именно вам — зависит от дохода и взноса. Посчитаю по всем и покажу лучшую.', E'info', 86),
  (E'/какплатеж', E'ℹ️ Как считается платёж', E'{{имя}}, платёж зависит от 3 вещей 👇\n\n• Сумма кредита (цена − первоначальный)\n• Ставка по программе\n• Срок (чем дольше — тем меньше в месяц, но больше переплата)\n\nСкажите цену квартиры и сколько готовы внести — пришлю точный платёж по подходящим программам.', E'info', 87)
